import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import productService from '../../services/productService';
import orderService from '../../services/orderService';
import { getMissingProfileFields, getProfileCompletion, isProfileComplete } from '../../utils/profileCompletion';

export default function DashboardOverview() {
    const { user } = useAuth();
    const { cartCount, cartSummary, addItem } = useCart();
    const [recentOrders, setRecentOrders] = useState([]);
    const [featuredProducts, setFeaturedProducts] = useState([]);
    const [productLoadError, setProductLoadError] = useState('');
    const [productNotice, setProductNotice] = useState('');
    const [addingProductId, setAddingProductId] = useState(null);
    const [recentlyAddedProductId, setRecentlyAddedProductId] = useState(null);
    const recentlyAddedTimerRef = useRef<number | null>(null);

    const extractCollection = (response) => {
        const payload = response?.data?.data;

        if (Array.isArray(payload)) {
            return payload;
        }

        if (Array.isArray(payload?.data)) {
            return payload.data;
        }

        if (Array.isArray(response?.data?.data?.data)) {
            return response.data.data.data;
        }

        return [];
    };

    useEffect(() => {
        let active = true;

        const loadOrders = async () => {
            try {
                const res = await orderService.getOrders({ page: 1 });
                if (!active) {
                    return;
                }

                const data = res?.data?.data?.data || [];
                setRecentOrders(data.slice(0, 5));
            } catch {
                if (active) {
                    setRecentOrders([]);
                }
            }
        };

        loadOrders();

        return () => {
            active = false;
        };
    }, []);

    useEffect(() => {
        if (!productNotice) {
            return undefined;
        }

        const timer = setTimeout(() => setProductNotice(''), 2000);
        return () => clearTimeout(timer);
    }, [productNotice]);

    useEffect(() => {
        let active = true;

        const loadProducts = async () => {
            let products = [];

            try {
                const res = await productService.getFeatured({ timeout: 12000 });
                products = extractCollection(res);
            } catch {
                try {
                    const fallbackRes = await productService.getAll(
                        {
                            per_page: 6,
                            sort_by: 'created_at',
                            sort_order: 'desc',
                        },
                        {
                            timeout: 12000,
                        }
                    );

                    products = extractCollection(fallbackRes);
                } catch {
                    if (active) {
                        setProductLoadError('Unable to load recommended products right now.');
                    }
                }
            }

            if (!active) {
                return;
            }

            setFeaturedProducts(products.slice(0, 6));
            if (products.length > 0) {
                setProductLoadError('');
            }
        };

        loadProducts();

        return () => {
            active = false;
        };
    }, []);

    const completion = getProfileCompletion(user);
    const missingFields = getMissingProfileFields(user);
    const profileReady = isProfileComplete(user);
    const welcomeName = user?.name?.trim() || user?.customer_info?.name?.trim() || user?.email?.split('@')[0] || 'Customer';
    const currency = (value) => new Intl.NumberFormat('en-PH', {
        style: 'currency',
        currency: 'PHP',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(Number(value || 0));

    const cartSubtotal = Number(cartSummary?.subtotal || 0);
    const cartShipping = Number(cartSummary?.shipping || 0);
    const cartTotal = Number(cartSummary?.total || 0);

    const totals = useMemo(() => {
        const totalOrders = recentOrders.length;
        const activeOrders = recentOrders.filter((order) => {
            const status = String(order.status || '').toLowerCase();
            return status === 'processing' || status === 'shipped';
        }).length;

        return {
            totalOrders,
            activeOrders,
        };
    }, [recentOrders]);

    const getProductImage = (product) => {
        if (Array.isArray(product?.images) && product.images.length > 0) {
            return product.images[0];
        }

        if (typeof product?.image_url === 'string' && product.image_url.trim() !== '') {
            return product.image_url;
        }

        return '/images/carvex.png';
    };

    const handleAddProduct = (product) => {
        if (addingProductId === product.id) {
            return;
        }

        setAddingProductId(product.id);

        window.setTimeout(() => {
            setAddingProductId((current) => (current === product.id ? null : current));
        }, 320);

        addItem(product.id, 1, {
                id: product.id,
                name: product.name,
                brand: product.brand,
                price: Number(product.price || 0),
                images: product.images,
            })
            .then(() => {
            setProductNotice(`${product.name} added to cart.`);
                setRecentlyAddedProductId(product.id);

                if (recentlyAddedTimerRef.current !== null) {
                    window.clearTimeout(recentlyAddedTimerRef.current);
                }

                recentlyAddedTimerRef.current = window.setTimeout(() => {
                    setRecentlyAddedProductId((current) => (current === product.id ? null : current));
                    recentlyAddedTimerRef.current = null;
                }, 900);
            })
            .catch(() => {
            setProductNotice('Unable to add item to cart right now.');
                setRecentlyAddedProductId((current) => (current === product.id ? null : current));
            });
    };

    useEffect(() => () => {
        if (recentlyAddedTimerRef.current !== null) {
            window.clearTimeout(recentlyAddedTimerRef.current);
        }
    }, []);

    return (
        <div className="dashboard-overview-shell">
            <section className="overview-header">
                <h1>Welcome back, {welcomeName}!</h1>
                <p>Here's what's happening with your CarVex account</p>
            </section>

            <section className="overview-stat-grid">
                <article className="overview-stat-card">
                    <div>
                        <p>Cart Items</p>
                        <strong>{cartCount}</strong>
                        <span>Items in your cart</span>
                    </div>
                    <div className="overview-stat-icon icon-cart" aria-hidden="true">
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <circle cx="9" cy="21" r="1" />
                            <circle cx="20" cy="21" r="1" />
                            <path d="M1 1h4l2.68 13.39A2 2 0 0 0 9.64 16h8.72a2 2 0 0 0 1.96-1.61L23 6H6" />
                        </svg>
                    </div>
                </article>

                <article className="overview-stat-card">
                    <div>
                        <p>Total Orders</p>
                        <strong>{totals.totalOrders}</strong>
                        <span>Orders placed</span>
                    </div>
                    <div className="overview-stat-icon icon-orders" aria-hidden="true">
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z" />
                            <path d="M3.3 7l8.7 5 8.7-5" />
                            <path d="M12 22V12" />
                        </svg>
                    </div>
                </article>

                <article className="overview-stat-card">
                    <div>
                        <p>Active Orders</p>
                        <strong>{totals.activeOrders}</strong>
                        <span>In progress</span>
                    </div>
                    <div className="overview-stat-icon icon-active" aria-hidden="true">
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <circle cx="12" cy="13" r="8" />
                            <path d="M12 13V9" />
                            <path d="M12 13l3 2" />
                            <path d="M9 2h6" />
                        </svg>
                    </div>
                </article>
            </section>

            <section className="overview-main-grid">
                <article className="overview-panel recent-orders-panel">
                    <div className="overview-panel-head">
                        <div>
                            <h2>Recent Orders</h2>
                            <p>Your latest purchases</p>
                        </div>
                        <Link to="/dashboard/orders" className="btn btn-outline-primary btn-sm">View All</Link>
                    </div>

                    {recentOrders.length === 0 ? (
                        <div className="overview-empty-state">
                            <div className="empty-icon" aria-hidden="true">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z" />
                                    <path d="M3.3 7l8.7 5 8.7-5" />
                                    <path d="M12 22V12" />
                                </svg>
                            </div>
                            <p>No orders yet</p>
                            <Link to="/dashboard/products" className="btn btn-primary btn-sm">Start Shopping</Link>
                        </div>
                    ) : (
                        <div className="dashboard-order-list">
                            {recentOrders.map((order) => (
                                <article key={order.id} className="dashboard-order-item">
                                    <div>
                                        <strong>{order.order_number || `Order #${order.id}`}</strong>
                                        <p>{new Date(order.created_at).toLocaleDateString()}</p>
                                    </div>
                                    <div>
                                        <span className={`order-status status-${order.status || 'processing'}`}>{order.status || 'processing'}</span>
                                        <strong>₱{Number(order.total_amount || 0).toFixed(2)}</strong>
                                    </div>
                                </article>
                            ))}
                        </div>
                    )}
                </article>

                <article className="overview-panel account-info-panel">
                    <div className="overview-panel-head">
                        <h2>Account Info</h2>
                    </div>

                    <div className="account-info-list">
                        <div>
                            <span>Name</span>
                            <strong>{user?.name || 'N/A'}</strong>
                        </div>
                        <div>
                            <span>Email</span>
                            <strong>{user?.email || 'N/A'}</strong>
                        </div>
                        <div>
                            <span>Phone</span>
                            <strong>{user?.phone || 'N/A'}</strong>
                        </div>
                    </div>

                    <div className="profile-progress-wrap">
                        <div className="progress-row">
                            <div className="progress-track">
                                <span style={{ width: `${completion}%` }} />
                            </div>
                            <strong>{completion}%</strong>
                        </div>
                        {!profileReady && missingFields.length > 0 && (
                            <p className="muted">Missing: {missingFields.join(', ')}</p>
                        )}
                    </div>

                    <Link to="/dashboard/profile" className="btn btn-outline-primary btn-sm btn-block">Edit Profile</Link>
                </article>
            </section>

            <section className="overview-bottom-grid">
                <article className="overview-panel recommended-panel">
                    <div className="overview-panel-head">
                        <div>
                            <h2>Recommended for You</h2>
                            <p>Popular car parts you might need</p>
                        </div>
                    </div>

                    {productLoadError && <div className="alert alert-warning">{productLoadError}</div>}
                    {productNotice && <div className="dashboard-notice">{productNotice}</div>}

                    {featuredProducts.length > 0 ? (
                        <div className="recommended-product-grid">
                            {featuredProducts.map((product) => (
                                <article key={product.id} className="recommended-product-card">
                                    <div className="recommended-product-image-wrap">
                                        <img src={getProductImage(product)} alt={product.name} />
                                    </div>
                                    <h3>{product.name}</h3>
                                    <p className="muted">{product.brand || 'CarVex'}</p>
                                    <strong>PHP {Number(product.price || 0).toFixed(2)}</strong>
                                    <button
                                        type="button"
                                        className="btn btn-primary btn-sm"
                                        onClick={() => handleAddProduct(product)}
                                        disabled={addingProductId === product.id}
                                    >
                                        {addingProductId === product.id
                                            ? 'Adding...'
                                            : recentlyAddedProductId === product.id
                                                ? 'Added'
                                                : 'Add to Cart'}
                                    </button>
                                </article>
                            ))}
                        </div>
                    ) : (
                        <div className="overview-empty-state">
                            <p>No products available right now.</p>
                            <Link to="/dashboard/products" className="btn btn-outline-primary btn-sm">Browse Products</Link>
                        </div>
                    )}
                </article>

                <article className="overview-panel quick-actions-panel">
                    <div className="overview-panel-head">
                        <div>
                            <h2>Cart Summary</h2>
                            <p>Review what you have saved and continue to checkout.</p>
                        </div>
                    </div>

                    <div className="account-info-list" style={{ marginBottom: '1rem' }}>
                        <div>
                            <span>Cart Items</span>
                            <strong>{cartCount}</strong>
                        </div>
                        <div>
                            <span>Subtotal</span>
                            <strong>{currency(cartSubtotal)}</strong>
                        </div>
                        <div>
                            <span>Shipping</span>
                            <strong>{currency(cartShipping)}</strong>
                        </div>
                        <div>
                            <span>Total</span>
                            <strong>{currency(cartTotal)}</strong>
                        </div>
                    </div>

                    {cartCount === 0 ? (
                        <div className="overview-empty-state" style={{ marginBottom: '1rem' }}>
                            <p>Your cart is empty right now.</p>
                            <Link to="/dashboard/products" className="btn btn-primary btn-sm">Browse Products</Link>
                        </div>
                    ) : (
                        <div className="quick-actions-list" style={{ marginBottom: '1rem' }}>
                            <Link to="/dashboard/cart" className="quick-action-link">
                                <span className="quick-action-icon" aria-hidden="true">
                                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M6 2l1.5 4h9L18 2" />
                                        <path d="M3 7h18l-1.5 12H4.5L3 7z" />
                                    </svg>
                                </span>
                                <span>Open Cart</span>
                            </Link>
                            <Link to="/dashboard/checkout" className="quick-action-link">
                                <span className="quick-action-icon" aria-hidden="true">
                                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M4 7h16" />
                                        <path d="M6 7l1 12h10l1-12" />
                                        <path d="M9 11v4" />
                                        <path d="M15 11v4" />
                                    </svg>
                                </span>
                                <span>Checkout Now</span>
                            </Link>
                        </div>
                    )}

                    <div className="overview-panel-head" style={{ marginTop: '0.4rem' }}>
                        <h2>Quick Actions</h2>
                    </div>

                    <div className="quick-actions-list">
                        <Link to="/dashboard/products" className="quick-action-link">
                            <span className="quick-action-icon" aria-hidden="true">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <circle cx="9" cy="21" r="1" />
                                    <circle cx="20" cy="21" r="1" />
                                    <path d="M1 1h4l2.68 13.39A2 2 0 0 0 9.64 16h8.72a2 2 0 0 0 1.96-1.61L23 6H6" />
                                </svg>
                            </span>
                            <span>Browse Products</span>
                        </Link>
                        <Link to="/dashboard/cart" className="quick-action-link">
                            <span className="quick-action-icon" aria-hidden="true">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M6 2l1.5 4h9L18 2" />
                                    <path d="M3 7h18l-1.5 12H4.5L3 7z" />
                                </svg>
                            </span>
                            <span>View Cart ({cartCount})</span>
                        </Link>
                        <Link to="/dashboard/orders" className="quick-action-link">
                            <span className="quick-action-icon" aria-hidden="true">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z" />
                                    <path d="M3.3 7l8.7 5 8.7-5" />
                                    <path d="M12 22V12" />
                                </svg>
                            </span>
                            <span>Track Orders</span>
                        </Link>
                    </div>
                </article>
            </section>
        </div>
    );
}
